import{_ as o,o as s,c as t,ae as a}from"./chunks/framework.BGHOrOyn.js";const u=JSON.parse('{"title":"Docker without root privileges","description":"","frontmatter":{},"headers":[],"relativePath":"snippets-and-scripts/install-scripts/install-docker-and-docker-compose/docker-without-root-privileges.md","filePath":"snippets-and-scripts/install-scripts/install-docker-and-docker-compose/docker-without-root-privileges.md"}'),i={name:"snippets-and-scripts/install-scripts/install-docker-and-docker-compose/docker-without-root-privileges.md"};function r(n,e,d,l,c,h){return s(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="docker-without-root-privileges" tabindex="-1">Docker without root privileges <a class="header-anchor" href="#docker-without-root-privileges" aria-label="Permalink to &quot;Docker without root privileges&quot;">​</a></h1><p>These optional post-installation procedures describe how to configure your Linux host machine to work better with Docker.</p><h2 id="manage-docker-as-a-non-root-user" tabindex="-1">Manage Docker as a non-root user <a class="header-anchor" href="#manage-docker-as-a-non-root-user" aria-label="Permalink to &quot;Manage Docker as a non-root user&quot;">​</a></h2><p>The Docker daemon binds to a Unix socket, not a TCP port. By default it&#39;s the <code>root</code> user that owns the Unix socket, and other users can only access it using <code>sudo</code>. The Docker daemon always runs as the <code>root</code> user.</p><p>If you don&#39;t want to preface the <code>docker</code> command with <code>sudo</code>, create a Unix group called <code>docker</code> and add users to it. When the Docker daemon starts, it creates a Unix socket accessible by members of the <code>docker</code> group. On some Linux distributions, the system automatically creates this group when installing Docker Engine using a package manager. In that case, there is no need for you to manually create the group.</p><blockquote><p><strong>Warning</strong></p><p>The <code>docker</code> group grants root-level privileges to the user. For details on how this impacts security in your system, see <a href="https://docs.docker.com/engine/security/#docker-daemon-attack-surface" target="_blank" rel="noreferrer">Docker Daemon Attack Surface</a>.</p></blockquote><blockquote><p><strong>Note</strong></p><p>To run Docker without root privileges, see <a href="https://docs.docker.com/engine/security/rootless/" target="_blank" rel="noreferrer">Run the Docker daemon as a non-root user (Rootless mode)</a>.</p></blockquote><h3 id="create-the-docker-group" tabindex="-1">Create the <code>docker</code> group <a class="header-anchor" href="#create-the-docker-group" aria-label="Permalink to &quot;Create the `docker` group&quot;">​</a></h3><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo groupadd docker</span></span></code></pre></div><h3 id="add-your-user-to-the-docker-group" tabindex="-1">Add your user to the <code>docker</code> group <a class="header-anchor" href="#add-your-user-to-the-docker-group" aria-label="Permalink to &quot;Add your user to the `docker` group&quot;">​</a></h3><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo usermod -aG docker $USER</span></span></code></pre></div><h3 id="re-evaluate-group-membership" tabindex="-1">Re-evaluate group membership <a class="header-anchor" href="#re-evaluate-group-membership" aria-label="Permalink to &quot;Re-evaluate group membership&quot;">​</a></h3><p>Log out and log back in so that your group membership is re-evaluated.</p><p>If you&#39;re running Linux in a virtual machine, it may be necessary to restart the virtual machine for changes to take effect.</p><p>You can also run the following command to activate the changes to groups:</p><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ newgrp docker</span></span></code></pre></div><h3 id="verify-that-you-can-run-docker-without-sudo" tabindex="-1">Verify that you can run Docker without <code>sudo</code> <a class="header-anchor" href="#verify-that-you-can-run-docker-without-sudo" aria-label="Permalink to &quot;Verify that you can run Docker without `sudo`&quot;">​</a></h3><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ docker run hello-world</span></span></code></pre></div><p>This command downloads a test image and runs it in a container. When the container runs, it prints a message and exits.</p><h3 id="fix-permissions-if-you-see-a-permissions-error" tabindex="-1">Fix permissions if you see a permissions error <a class="header-anchor" href="#fix-permissions-if-you-see-a-permissions-error" aria-label="Permalink to &quot;Fix permissions if you see a permissions error&quot;">​</a></h3><p>If you initially ran Docker CLI commands using <code>sudo</code> before adding your user to the <code>docker</code> group, you may see the following error:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WARNING: Error loading config file: /home/user/.docker/config.json - stat /home/user/.docker/config.json: permission denied</span></span></code></pre></div><p>This error indicates that the permission settings for the <code>~/.docker/</code> directory are incorrect, due to having used the <code>sudo</code> command earlier.</p><p>To fix this problem, either remove the <code>~/.docker/</code> directory (it&#39;s recreated automatically, but any custom settings are lost), or change its ownership and permissions using the following commands:</p><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo chown </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$USER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$USER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /home/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$USER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/.docker -R</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo chmod g+rwx </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> -R</span></span></code></pre></div><h2 id="configure-docker-to-start-on-boot-with-systemd" tabindex="-1">Configure Docker to start on boot with systemd <a class="header-anchor" href="#configure-docker-to-start-on-boot-with-systemd" aria-label="Permalink to &quot;Configure Docker to start on boot with systemd&quot;">​</a></h2><p>Many modern Linux distributions use <a href="https://systemd.io/" target="_blank" rel="noreferrer">systemd</a> to manage which services start when the system boots. On Debian and Ubuntu, the Docker service starts on boot by default. To automatically start Docker and containerd on boot for other Linux distributions using systemd, run the following commands:</p><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo systemctl enable docker.service</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo systemctl enable containerd.service</span></span></code></pre></div><p>To stop this behavior, use <code>disable</code> instead.</p><div class="language-console vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">console</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo systemctl disable docker.service</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ sudo systemctl disable containerd.service</span></span></code></pre></div><p>You can use systemd unit files to configure the Docker service on startup, for example to add an HTTP proxy, set a different directory or partition for the Docker runtime files, or other customizations. For an example, see <a href="https://docs.docker.com/engine/daemon/proxy/#systemd-unit-file" target="_blank" rel="noreferrer">Configure the daemon to use a proxy</a>.</p><h2 id="configure-default-logging-driver" tabindex="-1">Configure default logging driver <a class="header-anchor" href="#configure-default-logging-driver" aria-label="Permalink to &quot;Configure default logging driver&quot;">​</a></h2><p>Docker provides <a href="https://docs.docker.com/engine/logging/" target="_blank" rel="noreferrer">logging drivers</a> for collecting and viewing log data from all containers running on a host. The default logging driver, <code>json-file</code>, writes log data to JSON-formatted files on the host filesystem. Over time, these log files expand in size, leading to potential exhaustion of disk resources.</p><p>To avoid issues with overusing disk for log data, consider one of the following options:</p><ul><li>Configure the <code>json-file</code> logging driver to turn on <a href="https://docs.docker.com/engine/logging/drivers/json-file/" target="_blank" rel="noreferrer">log rotation</a>.</li><li>Use an <a href="https://docs.docker.com/engine/logging/configure/#configure-the-default-logging-driver" target="_blank" rel="noreferrer">alternative logging driver</a> such as the <a href="https://docs.docker.com/engine/logging/drivers/local/" target="_blank" rel="noreferrer">&quot;local&quot; logging driver</a> that performs log rotation by default.</li><li>Use a logging driver that sends logs to a remote logging aggregator.</li></ul><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li>Take a look at the <a href="https://docs.docker.com/get-started/workshop/" target="_blank" rel="noreferrer">Docker workshop</a> to learn how to build an image and run it as a containerized application.</li></ul>',37)])])}const g=o(i,[["render",r]]);export{u as __pageData,g as default};
